// src/play.rs  — full file

use crate::IpAddressType;
use crate::cp::cilium::provision_cilium;
use crate::cp::{ensure_cp_endpoint_resolves, verify_control_plane_endpoint};
use crate::expand_tilde;
use crate::prompt_yes_no;
